use path_tree::{Folder, Node};

#[test]
fn from_vec_builds_correct_tree() {
    let data = vec![("bgm/rain.ogg", 1), ("bgm/wind.ogg", 2), ("config.json", 3)];
    let folder = Folder::from_vec(data);
    let top_names: Vec<&str> = folder.iter().map(|(n, _)| n).collect();
    assert_eq!(top_names, vec!["bgm", "config.json"]);
    assert_eq!(
        folder.get("bgm/rain.ogg").and_then(|n| n.as_item()),
        Some(&1)
    );
    let bgm = folder.get("bgm").and_then(|n| n.as_folder()).unwrap();
    let bgm_children: Vec<&str> = bgm.iter().map(|(n, _)| n).collect();
    assert_eq!(bgm_children, vec!["rain.ogg", "wind.ogg"]);
}

#[test]
fn from_vec_deduplicates_same_paths() {
    let data = vec![("a/b/c", 10), ("a/b/c", 20)];
    let folder = Folder::from_vec(data);
    // dedup should keep the first value (10)
    assert_eq!(folder.get("a/b/c").and_then(|n| n.as_item()), Some(&10));
}

