#[test]
fn insert_creates_intermediate_folders() {
    let mut root: Folder<i32> = Folder::new();
    root.insert("a/b/c", Node::Item(42));
    assert!(root.get("a").and_then(|n| n.as_folder()).is_some());
    assert!(root.get("a/b").and_then(|n| n.as_folder()).is_some());
    assert_eq!(root.get("a/b/c").and_then(|n| n.as_item()), Some(&42));
}

#[test]
fn insert_replaces_existing_node_and_returns_old() {
    let mut root: Folder<i32> = Folder::new();
    assert!(root.insert("x/y", Node::Item(1)).is_none());
    let old = root
        .insert("x/y", Node::Item(2))
        .expect("expected old node");
    assert_eq!(old.into_item(), Some(1));
    assert_eq!(root.get("x/y").and_then(|n| n.as_item()), Some(&2));
}

#[test]
fn remove_leaf_returns_node_and_removes_empty_parent() {
    let mut root: Folder<i32> = Folder::new();
    root.insert("x/y", Node::Item(5));
    let removed = root.remove("x/y").expect("should remove leaf");
    assert_eq!(removed.into_item(), Some(5));
    assert!(root.get("x/y").is_none());
    // Parent directory should be removed when it becomes empty
    assert!(root.get("x").is_none());
    assert!(root.is_empty());
}

