#[test]
fn get_mut_allows_modification() {
    let mut root: Folder<i32> = Folder::new();
    root.insert("m/n", Node::Item(100));
    let node = root.get_mut("m/n").and_then(|n| n.as_item_mut()).unwrap();
    *node = 200;
    assert_eq!(root.get("m/n").and_then(|n| n.as_item()), Some(&200));
}

#[test]
fn deeply_nested_tree_accessible() {
    let mut root: Folder<i32> = Folder::new();
    let deep = (0..10)
        .map(|i| format!("d{}", i))
        .collect::<Vec<_>>()
        .join("/");
    root.insert(&deep, Node::Item(999));
    assert_eq!(root.get(&deep).and_then(|n| n.as_item()), Some(&999));
    // check intermediate layers exist
    let mut path = String::new();
    for i in 0..10 {
        if i > 0 {
            path.push('/');
        }
        path.push_str(&format!("d{}", i));
        let is_folder_or_item = root.get(&path);
        assert!(is_folder_or_item.is_some());
    }
}

#[test]
fn clone_and_debug() {
    let mut root = Folder::new();
    root.insert("a/b", Node::Item(1));
    root.insert("config.json", Node::Item(2));
    let clone = root.clone();
    // modify original
    root.insert("a/c", Node::Item(3));
    // clone should not have 'a/c'
    assert!(clone.get("a/c").is_none());
    // Debug contains keys
    let dbg = format!("{:?}", clone);
    assert!(dbg.contains("config.json"));
    assert!(dbg.contains("a"));
}

#[test]
fn into_iter_consumes_folder() {
    let folder = Folder::from_vec(vec![("f1", 1), ("f2", 2)]);
    let names_ref: Vec<_> = folder.iter().map(|(n, _)| n.to_string()).collect();
    let names_owned: Vec<_> = folder.into_iter().map(|(n, _)| n).collect();
    assert_eq!(names_ref, names_owned);
}
